mapper.insert:
INSERT INTO CART
    (
        cart_seq
        , user_seq
        , item_seq
        , quantity
        , reg_date
    )
VALUES
    (
      cart_seq.NEXTVAL
    , #{userSeq}
    , #{itemSeq}
    , #{quantity}
    , SYSDATE
    )

mapper.select:
SELECT COUNT(*) FROM CART
WHERE user_seq = #{userSeq}
  AND item_seq = #{itemSeq}
